window.activateLinks=function(e,r,t){for(var o=Object.assign({class:"active",selector:null,traverse:0},r),a=window.location.href.replace(window.location.protocol+"//"+window.location.host,"").split("/"),n=a.length,l=o.traverse<=0?n:n>=o.traverse?n-o.traverse:n;n>=l;){var c=a.join("/"),i=Array.from(e.querySelectorAll('a[href="'+c+'"]')).map(function(e){return e.parentElement});if(o.selector&&(i=i.flatMap(function(e){return Array.from(e.querySelectorAll(o.selector))})),i.length>0){i.forEach(function(e){e.classList.add(o.class)}),t&&t(i);break}n-=1,a=a.slice(0,n)}return e};
